-- Speaking Prompts (100 prompts: 20 per part)
CREATE TABLE IF NOT EXISTS speaking_prompts (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  part_number INTEGER NOT NULL CHECK (part_number BETWEEN 1 AND 5),
  task_type VARCHAR(50) NOT NULL,
  title VARCHAR(255) NOT NULL,
  passage TEXT,
  prompt TEXT NOT NULL,
  image_url VARCHAR(500),
  prep_seconds INTEGER DEFAULT 10,
  model_answer TEXT,
  hint_words TEXT[],
  order_index INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_speaking_prompts_part ON speaking_prompts(part_number);
CREATE INDEX IF NOT EXISTS idx_speaking_prompts_order ON speaking_prompts(part_number, order_index);

-- Practice History (all speaking/writing practice attempts)
CREATE TABLE IF NOT EXISTS practice_history (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  mode VARCHAR(20) NOT NULL CHECK (mode IN ('speaking', 'writing')),
  part_number INTEGER NOT NULL,
  prompt_id VARCHAR(100) NOT NULL,
  prompt_title VARCHAR(255) NOT NULL,
  prompt_content TEXT NOT NULL,
  user_answer TEXT NOT NULL DEFAULT '',
  ai_score INTEGER,
  ai_feedback TEXT,
  ai_errors TEXT[],
  ai_task_scores JSONB,
  ai_important_words TEXT[],
  ai_suggested_answer TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_practice_history_user ON practice_history(user_id);
CREATE INDEX IF NOT EXISTS idx_practice_history_mode ON practice_history(user_id, mode);
CREATE INDEX IF NOT EXISTS idx_practice_history_created ON practice_history(created_at DESC);

